const ADMIN_NUMBER = process.env.ADMIN_WHATSAPP || '[REDACTED_PHONE]'

// The bridge uses the self-chat user's format
function toChatId(phone: string): string {
  // If it's already got @, use as-is
  if (phone.includes('@')) return phone
  // Otherwise format for WhatsApp
  return `${phone}@s.whatsapp.net`
}

export async function sendWhatsApp(to: string, message: string): Promise<boolean> {
  const chatId = toChatId(to)
  try {
    const res = await fetch(`${BRIDGE_URL}/send`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chatId, message }),
    })
    if (!res.ok) {
      const text = await res.text()
      console.error('[WhatsApp] Send failed:', text.substring(0, 200))
      return false
    }
    return true
  } catch (err) {
    console.error('[WhatsApp] Error:', err)
    return false
  }
}

