  const msg = `🆕 *Nuevo pedido* #${order.id?.slice(0, 8)}\nTotal: ${order.total}\nPago: ${order.payment_method || 'whatsapp'}\n\nVer en el panel:\nhttps://el-viajero.paragu-ai.com/admin/pedidos`

  await sendWhatsApp(ADMIN_NUMBER, msg)
}

